import{c as a,Q as o,j as r,m as t}from"./chunks/framework.CPTW7DhK.js";const h=JSON.parse('{"title":"Requisitos de Hardware e Software — POS Fast","description":"Requisitos mínimos de hardware e software para instalação local do POS Fast by Desbravador","frontmatter":{"title":"Requisitos de Hardware e Software — POS Fast","description":"Requisitos mínimos de hardware e software para instalação local do POS Fast by Desbravador","system":"POS Fast by Desbravador","modality":"Instalação Local (On-Premise)","audience":"Cliente / Fornecedor de hardware / Equipe de TI"},"headers":[],"relativePath":"desbravador-posfast/local/requisitos-hardware.md","filePath":"desbravador-posfast/local/requisitos-hardware.md","lastUpdated":null}'),d={name:"desbravador-posfast/local/requisitos-hardware.md"};function s(i,e,n,l,c,u){return o(),r("div",null,[...e[0]||(e[0]=[t('<p><strong>Sistema:</strong> POS Fast by Desbravador<br><strong>Modalidade:</strong> Instalação Local (On-Premise)<br><strong>Público:</strong> Cliente / Fornecedor de hardware / Equipe de TI</p><hr><h2 id="historico-de-revisoes" tabindex="-1">Histórico de Revisões <a class="header-anchor" href="#historico-de-revisoes" aria-label="Permalink to &quot;Histórico de Revisões&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Versão</th><th>Data</th><th>Descrição</th><th>Responsável</th></tr></thead><tbody><tr><td>1.0</td><td>Fev/2022</td><td>Criação do documento e revisão</td><td>Andressa Celant</td></tr><tr><td>1.1</td><td>Ago/2022</td><td>Revisão do documento</td><td>Andressa Celant</td></tr><tr><td>1.2</td><td>Abr/2023</td><td>Atualização</td><td>Leonardo Mazzoneto</td></tr></tbody></table><hr><h2 id="_1-objetivo" tabindex="-1">1. Objetivo <a class="header-anchor" href="#_1-objetivo" aria-label="Permalink to &quot;1. Objetivo&quot;">​</a></h2><p>Este documento serve como guia para a preparação do ambiente de funcionamento do sistema POS Fast by Desbravador, abordando os requisitos técnicos de instalação e outras questões relacionadas.</p><p>Este descritivo pode ser repassado ao fornecedor de hardware selecionado e servirá como guia para a aquisição dos equipamentos. Os requisitos levam em consideração que os servidores serão utilizados exclusivamente pelos serviços relacionados ao POS Fast. Caso seja necessário compartilhar servidores com outros serviços ou softwares (ERPs, Web Servers, etc.), os requisitos dos demais serviços devem ser considerados no dimensionamento.</p><hr><h2 id="_2-responsabilidades" tabindex="-1">2. Responsabilidades <a class="header-anchor" href="#_2-responsabilidades" aria-label="Permalink to &quot;2. Responsabilidades&quot;">​</a></h2><h3 id="_2-1-desbravador-software-ltda" tabindex="-1">2.1 Desbravador Software Ltda. <a class="header-anchor" href="#_2-1-desbravador-software-ltda" aria-label="Permalink to &quot;2.1 Desbravador Software Ltda.&quot;">​</a></h3><ul><li>A instalação do software do servidor é realizada exclusivamente pelo Analista de Implantação da Desbravador.</li><li>A equipe Desbravador estará disponível para esclarecer dúvidas técnicas durante todo o período de implantação.</li></ul><h3 id="_2-2-cliente-licenciado" tabindex="-1">2.2 Cliente (LICENCIADO) <a class="header-anchor" href="#_2-2-cliente-licenciado" aria-label="Permalink to &quot;2.2 Cliente (LICENCIADO)&quot;">​</a></h3><ul><li>Providenciar os equipamentos conforme especificações deste documento, com sistema operacional previamente instalado e configurado.</li><li>Garantir o licenciamento dos sistemas operacionais e softwares adicionais utilizados.</li><li>Prover segurança física e lógica para servidores e estações de trabalho.</li><li>Disponibilizar técnico de hardware durante o período de implantação.</li><li>Garantir a instalação e configuração de periféricos (impressoras, centrais telefônicas, fechaduras eletrônicas) para as devidas integrações.</li><li>Realizar e manter rotinas de backup dos dados do sistema.</li></ul><blockquote><p>⚠️ <strong>Atenção</strong></p><ul><li>A Desbravador <strong>NÃO</strong> realiza montagem/desmontagem de hardware nem instalação de sistemas operacionais.</li><li>A segurança dos arquivos e dados do sistema é responsabilidade exclusiva de quem opera o sistema.</li><li>Operações indevidas, falhas nas rotinas de backup ou uso de mídia defeituosa são de responsabilidade do LICENCIADO.</li></ul></blockquote><hr><h2 id="_3-selecao-do-fornecedor-de-hardware" tabindex="-1">3. Seleção do Fornecedor de Hardware <a class="header-anchor" href="#_3-selecao-do-fornecedor-de-hardware" aria-label="Permalink to &quot;3. Seleção do Fornecedor de Hardware&quot;">​</a></h2><p>Ao selecionar o fornecedor de equipamentos, certifique-se de que ele oferece:</p><ul><li>Suporte técnico disponível 24 horas por dia.</li><li>Presença física na mesma cidade ou região próxima ao estabelecimento.</li><li>Garantia e assistência técnica dos equipamentos fornecidos.</li><li>Capacidade de assumir responsabilidade pelo sistema operacional, rede e banco de dados.</li><li>Referências de clientes e instalações anteriores verificáveis.</li></ul><hr><h2 id="_4-configuracoes-de-servidor-por-quantidade-de-usuarios" tabindex="-1">4. Configurações de Servidor por Quantidade de Usuários <a class="header-anchor" href="#_4-configuracoes-de-servidor-por-quantidade-de-usuarios" aria-label="Permalink to &quot;4. Configurações de Servidor por Quantidade de Usuários&quot;">​</a></h2><hr><h3 id="_4-1-ate-5-usuarios" tabindex="-1">4.1 Até 5 Usuários <a class="header-anchor" href="#_4-1-ate-5-usuarios" aria-label="Permalink to &quot;4.1 Até 5 Usuários&quot;">​</a></h3><blockquote><p>ℹ️ Nesta faixa, aplicação e banco de dados podem coexistir em um único servidor.</p></blockquote><table tabindex="0"><thead><tr><th>Campo</th><th>Especificação</th></tr></thead><tbody><tr><td><strong>Processador</strong></td><td>Intel Core i5 ou AMD X4 Quad-Core</td></tr><tr><td><strong>Memória RAM</strong></td><td>16 GB</td></tr><tr><td><strong>Sistema Operacional</strong></td><td>Microsoft Windows Server 2019 licenciado</td></tr><tr><td><strong>Banco de Dados</strong></td><td>PostgreSQL 11</td></tr></tbody></table><hr><h3 id="_4-2-de-6-a-10-usuarios" tabindex="-1">4.2 De 6 a 10 Usuários <a class="header-anchor" href="#_4-2-de-6-a-10-usuarios" aria-label="Permalink to &quot;4.2 De 6 a 10 Usuários&quot;">​</a></h3><blockquote><p>ℹ️ O uso de dois servidores separados é recomendado para melhor desempenho.</p></blockquote><h4 id="▸-servidor-de-aplicacao" tabindex="-1">▸ Servidor de Aplicação <a class="header-anchor" href="#▸-servidor-de-aplicacao" aria-label="Permalink to &quot;▸ Servidor de Aplicação&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Campo</th><th>Especificação</th></tr></thead><tbody><tr><td><strong>Placa-Mãe</strong></td><td>Compatível com expansão de memória RAM. Marcas de referência: Asus, Intel, Soyo, MSI, Gigabyte.</td></tr><tr><td><strong>Processador</strong></td><td>Intel Core i5-2310 S1155 2,9 GHz com 6 MB de cache · AMD AM3+ FX-Serie FX-4100 3,6 GHz com 12 MB de cache</td></tr><tr><td><strong>Memória RAM</strong></td><td>16 GB</td></tr><tr><td><strong>Sistema Operacional</strong></td><td>Microsoft Windows Server 2019 licenciado</td></tr><tr><td><strong>Banco de Dados</strong></td><td>PostgreSQL 11</td></tr></tbody></table><h4 id="▸-servidor-de-banco-de-dados" tabindex="-1">▸ Servidor de Banco de Dados <a class="header-anchor" href="#▸-servidor-de-banco-de-dados" aria-label="Permalink to &quot;▸ Servidor de Banco de Dados&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Campo</th><th>Especificação</th></tr></thead><tbody><tr><td><strong>Placa-Mãe</strong></td><td>Compatível com expansão de memória RAM. Marcas de referência: Asus, Intel, Soyo, MSI, Gigabyte.</td></tr><tr><td><strong>Processador</strong></td><td>Intel Core i5-2310 S1155 2,9 GHz com 6 MB de cache · AMD AM3+ FX-Serie FX-4100 3,6 GHz com 12 MB de cache</td></tr><tr><td><strong>Memória RAM</strong></td><td>16 GB</td></tr><tr><td><strong>Sistema Operacional</strong></td><td>Linux Debian (versão estável)</td></tr><tr><td><strong>Banco de Dados</strong></td><td>PostgreSQL 11</td></tr></tbody></table><hr><h3 id="_4-3-de-11-a-20-usuarios" tabindex="-1">4.3 De 11 a 20 Usuários <a class="header-anchor" href="#_4-3-de-11-a-20-usuarios" aria-label="Permalink to &quot;4.3 De 11 a 20 Usuários&quot;">​</a></h3><blockquote><p>⚠️ <strong>Obrigatório</strong> — 01 servidor Linux (banco de dados) e 01 servidor Windows (aplicação).</p></blockquote><h4 id="▸-servidor-de-aplicacao-1" tabindex="-1">▸ Servidor de Aplicação <a class="header-anchor" href="#▸-servidor-de-aplicacao-1" aria-label="Permalink to &quot;▸ Servidor de Aplicação&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Campo</th><th>Especificação</th></tr></thead><tbody><tr><td><strong>Placa-Mãe</strong></td><td>Compatível com expansão de memória RAM. Marcas de referência: Asus, Intel, Soyo, MSI, Gigabyte.</td></tr><tr><td><strong>Processador</strong></td><td>Intel Core i5-2310 S1155 2,9 GHz com 6 MB de cache</td></tr><tr><td><strong>Memória RAM</strong></td><td>16 GB</td></tr><tr><td><strong>Sistema Operacional</strong></td><td>Microsoft Windows Server 2019 licenciado</td></tr><tr><td><strong>Banco de Dados</strong></td><td>PostgreSQL 11</td></tr></tbody></table><h4 id="▸-servidor-de-banco-de-dados-1" tabindex="-1">▸ Servidor de Banco de Dados <a class="header-anchor" href="#▸-servidor-de-banco-de-dados-1" aria-label="Permalink to &quot;▸ Servidor de Banco de Dados&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Campo</th><th>Especificação</th></tr></thead><tbody><tr><td><strong>Placa-Mãe</strong></td><td>Compatível com expansão de memória RAM. Marcas de referência: Asus, Intel, Soyo, MSI, Gigabyte.</td></tr><tr><td><strong>Processador</strong></td><td>Intel Core i5-2310 S1155 2,9 GHz com 6 MB de cache</td></tr><tr><td><strong>Memória RAM</strong></td><td>16 GB</td></tr><tr><td><strong>Sistema Operacional</strong></td><td>Linux Debian (versão estável)</td></tr><tr><td><strong>Banco de Dados</strong></td><td>PostgreSQL 11</td></tr></tbody></table><hr><h3 id="_4-4-de-21-a-40-usuarios" tabindex="-1">4.4 De 21 a 40 Usuários <a class="header-anchor" href="#_4-4-de-21-a-40-usuarios" aria-label="Permalink to &quot;4.4 De 21 a 40 Usuários&quot;">​</a></h3><blockquote><p>⚠️ <strong>Obrigatório</strong> — 01 servidor Linux (banco de dados) e 01 servidor Windows (aplicação).</p></blockquote><h4 id="▸-servidor-de-aplicacao-2" tabindex="-1">▸ Servidor de Aplicação <a class="header-anchor" href="#▸-servidor-de-aplicacao-2" aria-label="Permalink to &quot;▸ Servidor de Aplicação&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Campo</th><th>Especificação</th></tr></thead><tbody><tr><td><strong>Placa-Mãe</strong></td><td>Compatível com expansão de memória RAM. Marcas de referência: Asus, Intel, Soyo, MSI, Gigabyte.</td></tr><tr><td><strong>Processador</strong></td><td>Intel Core i7-3770T 3,70 GHz com 8 MB de cache · AMD Phenom II X6 1075T 3,0 GHz, 6 núcleos, cache 9 MB, Socket AM3</td></tr><tr><td><strong>Memória RAM</strong></td><td>32 GB</td></tr><tr><td><strong>Sistema Operacional</strong></td><td>Microsoft Windows Server 2019 licenciado</td></tr><tr><td><strong>Banco de Dados</strong></td><td>PostgreSQL 11</td></tr></tbody></table><h4 id="▸-servidor-de-banco-de-dados-2" tabindex="-1">▸ Servidor de Banco de Dados <a class="header-anchor" href="#▸-servidor-de-banco-de-dados-2" aria-label="Permalink to &quot;▸ Servidor de Banco de Dados&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Campo</th><th>Especificação</th></tr></thead><tbody><tr><td><strong>Placa-Mãe</strong></td><td>Compatível com expansão de memória RAM. Marcas de referência: Asus, Intel, Soyo, MSI, Gigabyte.</td></tr><tr><td><strong>Processador</strong></td><td>Intel Core i7-3770T 3,70 GHz com 8 MB de cache · AMD Phenom II X6 1075T 3,0 GHz, 6 núcleos, cache 9 MB, Socket AM3</td></tr><tr><td><strong>Memória RAM</strong></td><td>32 GB</td></tr><tr><td><strong>Sistema Operacional</strong></td><td>Linux Debian (versão estável)</td></tr><tr><td><strong>Banco de Dados</strong></td><td>PostgreSQL 11</td></tr></tbody></table><hr><h3 id="_4-5-acima-de-40-usuarios" tabindex="-1">4.5 Acima de 40 Usuários <a class="header-anchor" href="#_4-5-acima-de-40-usuarios" aria-label="Permalink to &quot;4.5 Acima de 40 Usuários&quot;">​</a></h3><blockquote><p>⚠️ <strong>Obrigatório</strong> — 01 servidor Linux (banco de dados) e 01 servidor Windows (aplicação).</p></blockquote><h4 id="▸-servidor-de-aplicacao-3" tabindex="-1">▸ Servidor de Aplicação <a class="header-anchor" href="#▸-servidor-de-aplicacao-3" aria-label="Permalink to &quot;▸ Servidor de Aplicação&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Campo</th><th>Especificação</th></tr></thead><tbody><tr><td><strong>Placa-Mãe</strong></td><td>Compatível com expansão de memória RAM. Marcas de referência: Asus, Intel, Soyo, MSI, Gigabyte.</td></tr><tr><td><strong>Processador</strong></td><td>Intel Core i7-3770T 3,70 GHz com 8 MB de cache · AMD Phenom II X6 1075T 3,0 GHz, 6 núcleos, cache 9 MB, Socket AM3</td></tr><tr><td><strong>Memória RAM</strong></td><td>64 GB</td></tr><tr><td><strong>Sistema Operacional</strong></td><td>Microsoft Windows Server 2019 licenciado</td></tr><tr><td><strong>Banco de Dados</strong></td><td>PostgreSQL 11</td></tr></tbody></table><h4 id="▸-servidor-de-banco-de-dados-3" tabindex="-1">▸ Servidor de Banco de Dados <a class="header-anchor" href="#▸-servidor-de-banco-de-dados-3" aria-label="Permalink to &quot;▸ Servidor de Banco de Dados&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Campo</th><th>Especificação</th></tr></thead><tbody><tr><td><strong>Placa-Mãe</strong></td><td>Compatível com expansão de memória RAM. Marcas de referência: Asus, Intel, Soyo, MSI, Gigabyte.</td></tr><tr><td><strong>Processador</strong></td><td>Intel Core i7-3770T 3,70 GHz com 8 MB de cache · AMD Phenom II X6 1075T 3,0 GHz, 6 núcleos, cache 9 MB, Socket AM3</td></tr><tr><td><strong>Memória RAM</strong></td><td>64 GB</td></tr><tr><td><strong>Sistema Operacional</strong></td><td>Linux CentOS ou Debian com Samba configurado</td></tr><tr><td><strong>Banco de Dados</strong></td><td>PostgreSQL 11</td></tr></tbody></table><hr><h2 id="_5-estacoes-de-trabalho" tabindex="-1">5. Estações de Trabalho <a class="header-anchor" href="#_5-estacoes-de-trabalho" aria-label="Permalink to &quot;5. Estações de Trabalho&quot;">​</a></h2><p>A qualidade da estação de trabalho tem papel fundamental no desempenho percebido pelo usuário, pois é ela que processa a massa de dados enviada pelo servidor.</p><h3 id="_5-1-vida-util-e-processador" tabindex="-1">5.1 Vida Útil e Processador <a class="header-anchor" href="#_5-1-vida-util-e-processador" aria-label="Permalink to &quot;5.1 Vida Útil e Processador&quot;">​</a></h3><ul><li>Computadores devem ter no máximo <strong>3 anos de uso</strong>, principalmente em função do processador.</li><li>Considerar processadores <strong>Intel Core i3 ou superior</strong> ou <strong>AMD X4 Quad-Core</strong>.</li><li><strong>Desconsiderar</strong> processadores Celeron, Atom e demais de baixíssima performance.</li></ul><h3 id="_5-2-memoria-e-armazenamento" tabindex="-1">5.2 Memória e Armazenamento <a class="header-anchor" href="#_5-2-memoria-e-armazenamento" aria-label="Permalink to &quot;5.2 Memória e Armazenamento&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Cenário</th><th>Memória RAM</th><th>Disco</th></tr></thead><tbody><tr><td>Estações usando apenas o POS Fast</td><td>Mínimo 8 GB</td><td>500 GB</td></tr><tr><td>Estações com o POS Fast e outros aplicativos</td><td>Mínimo 16 GB</td><td>500 GB</td></tr></tbody></table><h3 id="_5-3-demais-requisitos" tabindex="-1">5.3 Demais Requisitos <a class="header-anchor" href="#_5-3-demais-requisitos" aria-label="Permalink to &quot;5.3 Demais Requisitos&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Componente</th><th>Especificação</th></tr></thead><tbody><tr><td><strong>Placa de Rede</strong></td><td>Gigabit Ethernet 100/1000 Mbps (pode ser on-board)</td></tr><tr><td><strong>Portas Seriais</strong></td><td>Obrigatório para conexão com impressoras fiscais</td></tr><tr><td><strong>Antivírus</strong></td><td>Obrigatório (solução licenciada)</td></tr><tr><td><strong>Sistema Operacional</strong></td><td>Microsoft Windows 10 ou superior, versão Professional, licenciado</td></tr></tbody></table><hr><h2 id="_6-ipdv-—-dispositivos-moveis" tabindex="-1">6. iPDV — Dispositivos Móveis <a class="header-anchor" href="#_6-ipdv-—-dispositivos-moveis" aria-label="Permalink to &quot;6. iPDV — Dispositivos Móveis&quot;">​</a></h2><p>O iPDV é o aplicativo para lançamento em dispositivos móveis. Requisitos mínimos:</p><ul><li>Sistema operacional Android 8.0 ou superior.</li><li>4 GB de memória RAM ou superior.</li><li>Tela de 6 polegadas ou maior.</li><li>Se utilizar leitura de QR Code: câmera com no mínimo 2 megapixels.</li><li>Se utilizar NFC de aproximação: o aparelho deve conter a funcionalidade. Tablets da linha A da Samsung não são compatíveis com NFC para este uso.</li></ul><hr><h2 id="_7-hardwares-complementares-todas-as-configuracoes" tabindex="-1">7. Hardwares Complementares (Todas as Configurações) <a class="header-anchor" href="#_7-hardwares-complementares-todas-as-configuracoes" aria-label="Permalink to &quot;7. Hardwares Complementares (Todas as Configurações)&quot;">​</a></h2><h3 id="_7-1-armazenamento" tabindex="-1">7.1 Armazenamento <a class="header-anchor" href="#_7-1-armazenamento" aria-label="Permalink to &quot;7.1 Armazenamento&quot;">​</a></h3><ul><li>2 discos HD SATA3 500 GB 7200 RPM 16 MB em cada servidor (marcas de referência: Seagate, Corsair).</li><li>Servidores e estações de trabalho com dados de missão crítica devem usar RAID Nível 1 ou 1+0.</li><li>Para servidores de aplicação, RAID 1, RAID 1+0 ou RAID 5 são aceitos.</li></ul><h3 id="_7-2-dispositivos-de-backup" tabindex="-1">7.2 Dispositivos de Backup <a class="header-anchor" href="#_7-2-dispositivos-de-backup" aria-label="Permalink to &quot;7.2 Dispositivos de Backup&quot;">​</a></h3><ul><li>HD externo, gravador de CD/DVD, Pen Drive ou fita.</li><li><strong>IMPORTANTE:</strong> dispositivos externos de backup devem ser conectados ao servidor apenas no momento da realização do backup.</li><li>Um local de backup externo (nuvem) deve ser configurado pela equipe de TI do cliente para backup completo do banco de dados e arquivos de aplicação.</li></ul><h3 id="_7-3-rede" tabindex="-1">7.3 Rede <a class="header-anchor" href="#_7-3-rede" aria-label="Permalink to &quot;7.3 Rede&quot;">​</a></h3><ul><li><strong>Placa de rede:</strong> Gigabit Ethernet 100/1000 Mbps (pode ser on-board). Marcas de referência: 3COM, Encore, TP-Link.</li><li><strong>Switch:</strong> portas 100/1000 Mbps. Marcas de referência: Dell, HP, 3COM, Encore, TP-Link.</li><li>⚠️ A velocidade de comunicação é limitada pelo componente mais lento — placa de rede e switch devem ter a mesma capacidade.</li><li>Recomenda-se redundância de placa de rede nos servidores.</li></ul><h3 id="_7-4-protecao-eletrica" tabindex="-1">7.4 Proteção Elétrica <a class="header-anchor" href="#_7-4-protecao-eletrica" aria-label="Permalink to &quot;7.4 Proteção Elétrica&quot;">​</a></h3><ul><li><strong>Nobreak (UPS)</strong> para o servidor — indispensável para proteger o banco de dados contra quedas de energia.</li></ul><hr><h2 id="_8-rede-e-diretrizes-de-comunicacao" tabindex="-1">8. Rede e Diretrizes de Comunicação <a class="header-anchor" href="#_8-rede-e-diretrizes-de-comunicacao" aria-label="Permalink to &quot;8. Rede e Diretrizes de Comunicação&quot;">​</a></h2><p>O POS Fast pode ser instalado on-premise, em datacenter ou em modelo híbrido. Independentemente da modalidade, a comunicação de rede deve ser cuidadosamente arquitetada. Os três requisitos fundamentais são:</p><h3 id="latencia" tabindex="-1">Latência <a class="header-anchor" href="#latencia" aria-label="Permalink to &quot;Latência&quot;">​</a></h3><p>Quantidade de atraso que uma solicitação leva para ser transferida entre dois pontos, medida em milissegundos (ms).</p><ul><li><strong>Recomendação:</strong> entre 1 ms e 80 ms entre a estação cliente e o servidor.</li></ul><h3 id="largura-de-banda" tabindex="-1">Largura de Banda <a class="header-anchor" href="#largura-de-banda" aria-label="Permalink to &quot;Largura de Banda&quot;">​</a></h3><p>Capacidade da rede de transferir dados, geralmente limitada pelo link de acesso de borda.</p><ul><li><strong>Recomendação:</strong> mínimo de 10 Mbps exclusivos para uso do sistema.</li><li>Avaliar a necessidade de link de acesso redundante para mitigar risco de interrupção única de rede.</li></ul><h3 id="jitter" tabindex="-1">Jitter <a class="header-anchor" href="#jitter" aria-label="Permalink to &quot;Jitter&quot;">​</a></h3><p>Variação no atraso de entrega de pacotes em rede, causando interrupção na sequência normal de troca de dados.</p><ul><li><strong>Recomendação:</strong> jitter abaixo de 20 ms para que o atraso não seja percebido pelo usuário.</li></ul><hr><h2 id="_9-seguranca" tabindex="-1">9. Segurança <a class="header-anchor" href="#_9-seguranca" aria-label="Permalink to &quot;9. Segurança&quot;">​</a></h2><p>Princípios gerais para utilização segura do POS Fast:</p><ul><li>Manter o software sempre atualizado, incluindo a versão mais recente do produto e patches aplicáveis.</li><li>Limitar os privilégios de usuário ao mínimo necessário para a execução de suas funções. Revisar periodicamente.</li><li>Instalar o software com segurança: use firewalls, protocolos seguros (TLS/SSL) e senhas seguras.</li></ul><hr><h2 id="_10-virtualizacao" tabindex="-1">10. Virtualização <a class="header-anchor" href="#_10-virtualizacao" aria-label="Permalink to &quot;10. Virtualização&quot;">​</a></h2><blockquote><p>⚠️ <strong>Atenção:</strong> A Desbravador não certificou nenhum de seus produtos em ambientes de virtualização VMware ou equivalentes.</p></blockquote><p>O suporte da Desbravador em ambientes virtualizados funciona da seguinte forma:</p><ul><li>Suporte prestado apenas para problemas que ocorrem no sistema operacional nativo ou demonstráveis como resultado direto da VM.</li><li>Para problemas conhecidos da Desbravador, a solução recomendada será para o SO nativo. Caso não funcione no ambiente VM, o cliente será encaminhado ao fornecedor da plataforma de virtualização.</li></ul><hr><h2 id="_11-acesso-remoto-quando-aplicavel" tabindex="-1">11. Acesso Remoto (Quando Aplicável) <a class="header-anchor" href="#_11-acesso-remoto-quando-aplicavel" aria-label="Permalink to &quot;11. Acesso Remoto (Quando Aplicável)&quot;">​</a></h2><p>Para estabelecimentos com banco de dados fora da empresa ou que necessitem de acesso externo via Terminal Service.</p><h3 id="_11-1-servidor-de-aplicacao" tabindex="-1">11.1 Servidor de Aplicação <a class="header-anchor" href="#_11-1-servidor-de-aplicacao" aria-label="Permalink to &quot;11.1 Servidor de Aplicação&quot;">​</a></h3><ul><li>Deve desempenhar o papel de Controlador de Domínio.</li><li>Deve administrar o serviço de Terminal Service (Remote Desktop Services).</li></ul><hr><h2 id="_12-perifericos-homologados" tabindex="-1">12. Periféricos Homologados <a class="header-anchor" href="#_12-perifericos-homologados" aria-label="Permalink to &quot;12. Periféricos Homologados&quot;">​</a></h2><p>O sistema possui integração desenvolvida e homologada com os seguintes periféricos:</p><ul><li>🏷️ <a href="./../../_shared/sat-mfe-homologados.html">Equipamentos SAT/MFE homologados</a></li><li>💳 <a href="./../../_shared/pinpads-homologados.html">Pinpads homologados</a></li><li>💳 <a href="./../../_shared/tef-homologados.html">Sistemas de TEF homologados</a></li><li>🖨️ <a href="./../../_shared/impressoras-homologadas.html">Impressoras não fiscais e fiscais homologadas</a></li></ul><hr><h2 id="_13-contato-e-suporte" tabindex="-1">13. Contato e Suporte <a class="header-anchor" href="#_13-contato-e-suporte" aria-label="Permalink to &quot;13. Contato e Suporte&quot;">​</a></h2><p><strong>Desbravador Software Ltda.</strong><br> 🌐 <a href="https://www.desbravador.com.br" target="_blank" rel="noreferrer">www.desbravador.com.br</a></p><p>Para dúvidas técnicas durante a implantação, a equipe Desbravador estará disponível para esclarecimentos.</p>',110)])])}const p=a(d,[["render",s]]);export{h as __pageData,p as default};
